from __future__ import annotations

import argparse
import csv
import json
import subprocess
import sys
from datetime import date, datetime
from pathlib import Path
from typing import Any
import re

WORKSPACE = Path.home() / ".openclaw" / "workspace"
QUANT_ROOT = WORKSPACE / "quant_projects" / "personal-a-share-research-system"
DEFAULT_OUTPUT_DIR = QUANT_ROOT / "research" / "reports"
SELECTION_CONFIG = QUANT_ROOT / "config" / "ths_local_holdings_selection.json"
SNAPSHOT_DIRNAME = "fusion_input_snapshots"

STOCK_DAILY_DIR = WORKSPACE / "skills" / "stock-daily-report"
STOCK_DAILY_CONFIG = STOCK_DAILY_DIR / "config.json"
STOCK_WATCHER_WATCHLIST = Path.home() / ".clawdbot" / "stock_watcher" / "watchlist.txt"
AKSHARE_STOCK_CLI = Path.home() / ".openclaw" / "skills" / "akshare-stock" / "scripts" / "stock_cli.py"
STOCK_WATCHER_SUMMARY = (
    Path.home() / ".openclaw" / "skills" / "stock-watcher" / "scripts" / "summarize_performance.py"
)
VALID_SOURCE_TYPES = {"web", "excel", "ledger", "other"}


class HoldingsInputError(RuntimeError):
    """Raised when holdings input is missing, ambiguous, or schema-invalid."""


def normalize_code(raw: Any) -> str | None:
    s = str(raw or "").strip().upper()
    if not s:
        return None
    if len(s) >= 8 and s[:2] in {"SH", "SZ", "BJ", "HK"} and s[2:].isdigit():
        s = s[2:]
    if "." in s:
        s = s.split(".", 1)[0]

    s = re.sub(r"\D", "", s)
    if len(s) in {5, 6}:
        return s
    return None


def dedupe(items: list[str]) -> list[str]:
    seen = set()
    out: list[str] = []
    for x in items:
        if x in seen:
            continue
        seen.add(x)
        out.append(x)
    return out


def latest_file(root: Path, pattern: str) -> Path | None:
    files = [p for p in root.glob(pattern) if p.is_file()]
    if not files:
        return None
    files.sort(key=lambda p: p.stat().st_mtime, reverse=True)
    return files[0]


def infer_source_type(path: Path) -> str:
    name = path.name.lower()
    if path.suffix.lower() in {".xls", ".xlsx"}:
        return "excel"
    if name.startswith("ths_selected_holdings") or name.startswith("ths_app_holdings"):
        return "ledger"
    if name.startswith("ths_web_holding_count_fix"):
        return "web"
    return "other"


def first_nonempty(row: dict[str, Any], keys: list[str]) -> str:
    for key in keys:
        value = row.get(key)
        if value is None:
            continue
        text = str(value).strip()
        if text:
            return text
    return ""


def parse_float(value: Any) -> float | None:
    text = str(value or "").strip()
    if not text:
        return None
    try:
        return float(text.replace(",", ""))
    except Exception:
        return None


def parse_rows_from_csv(path: Path, source_type: str) -> tuple[list[dict[str, Any]], list[str]]:
    issues: list[str] = []
    rows: list[dict[str, Any]] = []

    with path.open("r", encoding="utf-8-sig", newline="") as f:
        reader = csv.DictReader(f)
        fieldnames = reader.fieldnames or []
        if not fieldnames:
            raise HoldingsInputError(f"CSV 无表头，无法解析: {path}")

        code_keys = ["symbol", "ts_code", "code", "stock_code", "ticker"]
        if not any(key in fieldnames for key in code_keys):
            raise HoldingsInputError(
                f"CSV 缺少关键代码列(symbol/ts_code/code/stock_code/ticker): {path} | headers={fieldnames}"
            )

        qty_keys = ["quantity", "qty", "shares", "position", "volume"]
        price_keys = ["cost_price", "cost", "avg_cost", "price"]
        name_keys = ["name", "stock_name", "security_name"]
        asset_type_keys = ["asset_type", "type", "instrument_type"]

        for idx, row in enumerate(reader, start=2):
            if not any(str(v or "").strip() for v in row.values()):
                continue

            raw_code = first_nonempty(row, code_keys)
            code = normalize_code(raw_code)
            if not raw_code or not code:
                issues.append(f"line {idx}: invalid code raw={raw_code!r}")
                continue

            row_source = first_nonempty(row, ["source"]) or source_type
            quantity = parse_float(first_nonempty(row, qty_keys))
            cost_price = parse_float(first_nonempty(row, price_keys))
            asset_type = first_nonempty(row, asset_type_keys).lower() or "stock"
            rows.append(
                {
                    "code": code,
                    "raw_code": raw_code,
                    "symbol": raw_code,
                    "name": first_nonempty(row, name_keys),
                    "quantity": quantity,
                    "cost_price": cost_price,
                    "asset_type": asset_type,
                    "source": row_source,
                    "origin_file": str(path),
                }
            )

    return rows, issues


def parse_rows_from_json(path: Path, source_type: str) -> tuple[list[dict[str, Any]], list[str], dict[str, Any]]:
    issues: list[str] = []
    meta: dict[str, Any] = {}
    payload = json.loads(path.read_text(encoding="utf-8"))

    if isinstance(payload, dict) and isinstance(payload.get("codes"), list):
        meta = {
            "reported_source": payload.get("source", ""),
            "generated_at": payload.get("generated_at", ""),
            "holding_count": payload.get("holding_count"),
            "note": payload.get("note", ""),
        }
        rows: list[dict[str, Any]] = []
        for idx, raw_code in enumerate(payload.get("codes") or [], start=1):
            code = normalize_code(raw_code)
