                    "asset_type": "stock",
                    "source": source_type,
                    "origin_file": str(path),
                }
            )
        return rows, issues, meta

    if isinstance(payload, list):
        rows: list[dict[str, Any]] = []
        for idx, item in enumerate(payload, start=1):
            if not isinstance(item, dict):
                issues.append(f"list[{idx}] is not an object")
                continue
            raw_code = first_nonempty(item, ["symbol", "ts_code", "code", "stock_code", "ticker"])
            code = normalize_code(raw_code)
            if not raw_code or not code:
                issues.append(f"list[{idx}] invalid code raw={raw_code!r}")
                continue
            rows.append(
                {
                    "code": code,
                    "raw_code": raw_code,
                    "symbol": raw_code,
                    "name": first_nonempty(item, ["name", "stock_name", "security_name"]),
                    "quantity": parse_float(first_nonempty(item, ["quantity", "qty", "shares", "position", "volume"])),
                    "cost_price": parse_float(first_nonempty(item, ["cost_price", "cost", "avg_cost", "price"])),
                    "asset_type": first_nonempty(item, ["asset_type", "type", "instrument_type"]).lower() or "stock",
                    "source": first_nonempty(item, ["source"]) or source_type,
                    "origin_file": str(path),
                }
            )
        return rows, issues, meta

    raise HoldingsInputError(f"JSON schema 不受支持: {path}")


def load_input_bundle_from_file(path: Path, source_type: str | None = None) -> dict[str, Any]:
    if not path.exists():
        raise HoldingsInputError(f"输入文件不存在: {path}")

    resolved_source = source_type or infer_source_type(path)
    if resolved_source not in VALID_SOURCE_TYPES:
        raise HoldingsInputError(f"非法 source_type={resolved_source!r}，必须是 {sorted(VALID_SOURCE_TYPES)}")

    if path.suffix.lower() == ".csv":
        rows, issues = parse_rows_from_csv(path, resolved_source)
        meta: dict[str, Any] = {}
    elif path.suffix.lower() == ".json":
        rows, issues, meta = parse_rows_from_json(path, resolved_source)
    else:
        raise HoldingsInputError(f"暂不支持的输入格式: {path.suffix} | file={path}")

    bundle = {
        "input_file": str(path),
        "input_name": path.name,
        "source_type": resolved_source,
        "rows": rows,
        "issues": issues,
        "meta": meta,
    }
    validate_input_bundle(bundle)
    return bundle


def validate_input_bundle(bundle: dict[str, Any]) -> None:
    rows = bundle.get("rows") or []
    issues = bundle.get("issues") or []
    source_type = bundle.get("source_type")
    input_file = bundle.get("input_file") or "-"

    if source_type not in VALID_SOURCE_TYPES:
        raise HoldingsInputError(f"source_type 非法: {source_type!r} | file={input_file}")
    if issues:
        raise HoldingsInputError(
            "输入 schema 非法，发现不可解析行："
            + "; ".join(issues[:8])
            + (" ..." if len(issues) > 8 else "")
        )
    if not rows:
        raise HoldingsInputError(f"持仓输入为空: {input_file}")

    unique_codes = dedupe([str(row.get("code") or "") for row in rows if row.get("code")])
    if not unique_codes:
        raise HoldingsInputError(f"没有可用证券代码: {input_file}")

    if source_type == "web":
        reported_source = str((bundle.get("meta") or {}).get("reported_source") or "").strip()
        if not reported_source:
            raise HoldingsInputError(f"web 输入缺少 source 描述: {input_file}")

    if source_type == "ledger":
        unique_row_sources = dedupe([str(row.get("source") or "").strip() for row in rows if str(row.get("source") or "").strip()])
        if not unique_row_sources:
            raise HoldingsInputError(f"ledger 输入缺少逐行 source，无法校验账本来源: {input_file}")
        if len(unique_row_sources) != 1:
            raise HoldingsInputError(
